import React from "react";

const services = {
  "🏨 Travel & Stay": [
    {
      id: 1,
      name: "Hotel Booking",
      description: "Book the best hotels at your favorite destinations.",
      image: "https://images.unsplash.com/photo-1568605114967-8130f3a36994?fit=crop&w=400",
    },
    {
      id: 2,
      name: "Tour Guides",
      description: "Get local guides to explore cities like a pro.",
      image: "https://images.unsplash.com/photo-1438761681033-6461ffad8d80?fit=crop&w=400",
    },
  ],

  "💄 Beauty & Lifestyle": [
    {
      id: 3,
      name: "Makeup & Salon",
      description: "Professional hair and makeup services at your doorstep.",
      image: "https://images.unsplash.com/photo-1508214751196-bcfd4ca60f91?fit=crop&w=400",
    },
  ],

  "🚗 Transport & Tours": [
    {
      id: 4,
      name: "Car Rentals",
      description: "Rent cars for your trips with flexible options.",
      image: "https://images.unsplash.com/photo-1533473359331-0135ef1b58bf?fit=crop&w=400",
    },
  ],
};

function Services() {
  return (
    <div style={{ padding: "40px 20px", backgroundColor: "#fafafa" }}>
      <h1 style={{ textAlign: "center", fontSize: "36px", marginBottom: "30px", color: "#333" }}>
        Our Services
      </h1>

      {Object.entries(services).map(([category, items]) => (
        <div key={category} style={{ marginBottom: "50px" }}>
          <h2
            style={{
              fontSize: "28px",
              color: "#ff385c",
              marginBottom: "20px",
              textAlign: "center",
              textDecoration: "underline",
            }}
          >
            {category}
          </h2>

          <div
            style={{
              display: "flex",
              justifyContent: "center",
              flexWrap: "wrap",
              gap: "25px",
            }}
          >
            {items.map((service) => (
              <div
                key={service.id}
                style={{
                  border: "1px solid #ddd",
                  borderRadius: "15px",
                  width: "300px",
                  background: "#fff",
                  boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
                  overflow: "hidden",
                  transition: "transform 0.3s ease, box-shadow 0.3s ease",
                  cursor: "pointer",
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.transform = "scale(1.05)";
                  e.currentTarget.style.boxShadow = "0 8px 16px rgba(0,0,0,0.15)";
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.transform = "scale(1)";
                  e.currentTarget.style.boxShadow = "0 4px 10px rgba(0,0,0,0.1)";
                }}
              >
                <img
                  src={service.image}
                  alt={service.name}
                  style={{ width: "100%", height: "200px", objectFit: "cover" }}
                />
                <div style={{ padding: "15px" }}>
                  <h3 style={{ color: "#222", fontSize: "20px", marginBottom: "10px" }}>
                    {service.name}
                  </h3>
                  <p style={{ color: "#555", fontSize: "14px", lineHeight: "1.5" }}>
                    {service.description}
                  </p>
                  <button
                    style={{
                      marginTop: "10px",
                      padding: "8px 16px",
                      border: "none",
                      borderRadius: "5px",
                      background: "#ff385c",
                      color: "white",
                      cursor: "pointer",
                      fontWeight: "bold",
                    }}
                  >
                    Learn More
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}

export default Services;
